import{_ as o,o as t,c as a,ag as i}from"./chunks/framework.CTpQozEL.js";const h=JSON.parse('{"title":"사용량 추적","description":"사용량 추적 표면 및 자격 증명 요구사항","frontmatter":{"title":"사용량 추적","description":"사용량 추적 표면 및 자격 증명 요구사항"},"headers":[],"relativePath":"concepts/usage-tracking.md","filePath":"concepts/usage-tracking.md","lastUpdated":null}'),c={name:"concepts/usage-tracking.md"};function l(n,e,d,s,r,u){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="사용량-추적" tabindex="-1">사용량 추적 <a class="header-anchor" href="#사용량-추적" aria-label="Permalink to &quot;사용량 추적&quot;">​</a></h1><h2 id="이것이란" tabindex="-1">이것이란 <a class="header-anchor" href="#이것이란" aria-label="Permalink to &quot;이것이란&quot;">​</a></h2><ul><li>프로바이더의 사용량 엔드포인트에서 직접 프로바이더 사용량/할당량을 가져옵니다.</li><li>예상 비용 없음. 프로바이더가 보고하는 창만.</li><li>사람이 읽을 수 있는 상태 출력은 업스트림 API가 소비된 할당량, 남은 할당량 또는 원시 카운트만 보고하는 경우에도 <code>X% left</code>로 정규화됩니다.</li><li>세션 수준 <code>/status</code> 및 <code>session_status</code>는 라이브 세션 스냅샷이 희박할 때 최신 트랜스크립트 사용량 항목으로 폴백할 수 있습니다. 해당 폴백은 누락된 토큰/캐시 카운터를 채우고, 활성 런타임 모델 레이블을 복원할 수 있으며, 세션 메타데이터가 누락되거나 더 작을 때 더 큰 프롬프트 지향 합계를 선호합니다. 기존 0이 아닌 라이브 값은 여전히 우선합니다.</li></ul><h2 id="표시되는-위치" tabindex="-1">표시되는 위치 <a class="header-anchor" href="#표시되는-위치" aria-label="Permalink to &quot;표시되는 위치&quot;">​</a></h2><ul><li>채팅에서 <code>/status</code>: 세션 토큰 + 예상 비용 (API 키만)이 있는 이모지가 풍부한 상태 카드. 프로바이더 사용량은 사용 가능한 경우 <strong>현재 모델 프로바이더</strong>에 대해 정규화된 <code>X% left</code> 창으로 표시됩니다.</li><li>채팅에서 <code>/usage off|tokens|full</code>: 응답별 사용량 푸터 (OAuth는 토큰만 표시).</li><li>채팅에서 <code>/usage cost</code>: OpenClaw 세션 로그에서 집계된 로컬 비용 요약.</li><li>CLI: <code>openclaw status --usage</code>는 프로바이더별 전체 분석을 출력합니다.</li><li>CLI: <code>openclaw channels list</code>는 프로바이더 구성 옆에 동일한 사용량 스냅샷을 출력합니다 (<code>--no-usage</code>로 건너뛸 수 있음).</li><li>macOS 메뉴바: 컨텍스트 아래의 &quot;Usage&quot; 섹션 (사용 가능한 경우에만).</li></ul><h2 id="프로바이더-자격-증명" tabindex="-1">프로바이더 + 자격 증명 <a class="header-anchor" href="#프로바이더-자격-증명" aria-label="Permalink to &quot;프로바이더 + 자격 증명&quot;">​</a></h2><ul><li><strong>Anthropic (Claude)</strong>: 인증 프로필의 OAuth 토큰.</li><li><strong>GitHub Copilot</strong>: 인증 프로필의 OAuth 토큰.</li><li><strong>Gemini CLI</strong>: 인증 프로필의 OAuth 토큰. <ul><li>JSON 사용량은 <code>stats</code>로 폴백합니다. <code>stats.cached</code>는 <code>cacheRead</code>로 정규화됩니다.</li></ul></li><li><strong>OpenAI Codex</strong>: 인증 프로필의 OAuth 토큰 (있는 경우 accountId 사용).</li><li><strong>MiniMax</strong>: API 키 또는 MiniMax OAuth 인증 프로필. OpenClaw는 <code>minimax</code>, <code>minimax-cn</code>, <code>minimax-portal</code>을 동일한 MiniMax 할당량 표면으로 처리하며, 저장된 MiniMax OAuth가 있으면 선호하고 그렇지 않으면 <code>MINIMAX_CODE_PLAN_KEY</code>, <code>MINIMAX_CODING_API_KEY</code>, <code>MINIMAX_API_KEY</code>로 폴백합니다. MiniMax의 원시 <code>usage_percent</code> / <code>usagePercent</code> 필드는 <strong>남은</strong> 할당량을 의미하므로 OpenClaw는 표시 전에 반전합니다. 카운트 기반 필드가 있으면 우선합니다. <ul><li>코딩 플랜 창 레이블은 있는 경우 프로바이더 hours/minutes 필드에서 가져오고, 그런 다음 <code>start_time</code> / <code>end_time</code> 범위로 폴백합니다.</li><li>코딩 플랜 엔드포인트가 <code>model_remains</code>를 반환하는 경우, OpenClaw는 채팅 모델 항목을 선호하고, 명시적 <code>window_hours</code> / <code>window_minutes</code> 필드가 없을 때 타임스탬프에서 창 레이블을 파생하며, 계획 레이블에 모델 이름을 포함합니다.</li></ul></li><li><strong>Xiaomi MiMo</strong>: env/구성/인증 저장소를 통한 API 키 (<code>XIAOMI_API_KEY</code>).</li><li><strong>z.ai</strong>: env/구성/인증 저장소를 통한 API 키.</li></ul><p>사용 가능한 프로바이더 사용량 인증이 해결되지 않으면 사용량이 숨겨집니다. 프로바이더는 플러그인별 사용량 인증 로직을 제공할 수 있습니다. 그렇지 않으면 OpenClaw는 인증 프로필, 환경 변수, 구성에서 일치하는 OAuth/API 키 자격 증명으로 폴백합니다.</p>',8)])])}const g=o(c,[["render",l]]);export{h as __pageData,g as default};
